namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature available: dark mode.", DateTime.UtcNow.AddMinutes(-2)));
    }

    public List<Notification> GetNotifications()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    public List<Notification> GetNotificationsSince(int lastId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// </summary>
    public void SimulateNewNotification()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Server maintenance scheduled.",
            "Your export is ready to download.",
            "Reminder: meeting in 15 minutes.",
            "New comment on your article.",
        };

        lock (_lock)
        {
            var msg = messages[_nextId % messages.Length];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject NotificationsApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationsApp.Services.Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        // Load initial notifications during prerender AND interactive init.
        // The data is cheap and identical both times, satisfying the
        // "initial data appears in server-rendered HTML" requirement.
        _notifications = NotificationService.GetNotifications();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is live/interactive,
            // never during static SSR prerender. Safe to start polling here.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        var lastId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;

        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct).ConfigureAwait(false);

            // Simulate the service receiving new data periodically
            NotificationService.SimulateNewNotification();

            var newer = NotificationService.GetNotificationsSince(lastId);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                lastId = newer.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

